import xml.etree.ElementTree as ET
import os, re

ns = {
    'a': 'http://schemas.openxmlformats.org/drawingml/2006/main',
    'r': 'http://schemas.openxmlformats.org/officeDocument/2006/relationships',
    'p': 'http://schemas.openxmlformats.org/presentationml/2006/main',
}

slides_dir = '/Users/admin/unpacked_pptx/ppt/slides'

def get_sp_text(sp):
    texts = []
    for t in sp.findall('.//a:t', ns):
        if t.text:
            texts.append(t.text)
    return ''.join(texts)

def get_rect(sp):
    """Get position and size of a shape"""
    spPr = sp.find('.//p:spPr', ns) or sp.find('.//a:spPr', ns)
    if spPr is None:
        return None
    xfrm = spPr.find('a:xfrm', ns)
    if xfrm is None:
        return None
    off = xfrm.find('a:off', ns)
    ext = xfrm.find('a:ext', ns)
    if off is not None and ext is not None:
        return {
            'x': int(off.get('x', 0)),
            'y': int(off.get('y', 0)),
            'cx': int(ext.get('cx', 0)),
            'cy': int(ext.get('cy', 0))
        }
    return None

def emu_to_inches(emu):
    return emu / 914400

def get_fill_info(sp):
    """Get background/fill color of a shape"""
    spPr = sp.find('.//p:spPr', ns) or sp.find('.//a:spPr', ns)
    if spPr is None:
        return None
    solidFill = spPr.find('.//a:solidFill', ns)
    if solidFill is not None:
        srgb = solidFill.find('.//a:srgbClr', ns)
        if srgb is not None:
            return f"#{srgb.get('val')}"
    return None

def get_text_colors(sp):
    """Get text colors used in a shape"""
    colors = set()
    for r in sp.findall('.//a:r', ns):
        rPr = r.find('a:rPr', ns)
        if rPr is not None:
            solidFill = rPr.find('a:solidFill', ns)
            if solidFill is not None:
                srgb = solidFill.find('a:srgbClr', ns)
                if srgb is not None:
                    colors.add(f"#{srgb.get('val')}")
    for endParaRPr in sp.findall('.//a:endParaRPr', ns):
        solidFill = endParaRPr.find('a:solidFill', ns)
        if solidFill is not None:
            srgb = solidFill.find('a:srgbClr', ns)
            if srgb is not None:
                colors.add(f"#{srgb.get('val')}")
    return colors

def get_font_sizes(sp):
    sizes = set()
    for r in sp.findall('.//a:r', ns):
        rPr = r.find('a:rPr', ns)
        if rPr is not None:
            sz = rPr.get('sz')
            if sz:
                sizes.add(int(sz))
    return sizes

def get_text_box_props(sp):
    """Get text box properties including margins"""
    bodyPr = sp.find('.//p:bodyPr', ns) or sp.find('.//a:bodyPr', ns)
    if bodyPr is not None:
        return {
            'lIns': bodyPr.get('lIns'),
            'rIns': bodyPr.get('rIns'),
            'tIns': bodyPr.get('tIns'),
            'bIns': bodyPr.get('bIns'),
            'wrap': bodyPr.get('wrap'),
            'autofit': bodyPr.find('a:normAutofit', ns) is not None or bodyPr.find('a:spAutoFit', ns) is not None
        }
    return {}

def get_shape_type(sp):
    """Determine the type of shape"""
    if sp.find('.//p:ph', ns) is not None:
        return 'placeholder'
    if sp.find('.//p:nvSpPr/p:cNvSpPr', ns) is not None:
        spPr = sp.find('.//p:nvSpPr/p:cNvSpPr', ns)
        txBox = spPr.get('txBox', '0')
        if txBox == '1':
            return 'textbox'
    if sp.tag == '{http://schemas.openxmlformats.org/presentationml/2006/main}pic':
        return 'picture'
    if sp.tag == '{http://schemas.openxmlformats.org/presentationml/2006/main}graphicFrame':
        return 'chart'
    # Check if it's a group shape
    if sp.tag == '{http://schemas.openxmlformats.org/presentationml/2006/main}grpSp':
        return 'group'
    return 'shape'

def parse_slide(slide_num):
    slide_path = os.path.join(slides_dir, f'slide{slide_num}.xml')
    tree = ET.parse(slide_path)
    root = tree.getroot()

    # Get slide dimensions from the presentation
    slide_w = 12192000  # 13.33 inches (widescreen)
    slide_h = 6858000   # 7.5 inches

    elements = []

    # Find all shapes
    for sp in root.iter():
        tag = tag_local(sp.tag)

        # Skip non-shape elements
        if tag not in ['sp', 'pic', 'grpSp', 'graphicFrame', 'cxnSp']:
            continue

        rect = get_rect(sp)
        if rect is None:
            continue

        text = get_sp_text(sp) if tag == 'sp' else ''
        stype = get_shape_type(sp) if tag == 'sp' else tag
        fill = get_fill_info(sp) if tag == 'sp' else None
        tcolors = get_text_colors(sp) if tag == 'sp' else set()
        fsizes = get_font_sizes(sp) if tag == 'sp' else set()
        tbprops = get_text_box_props(sp) if tag == 'sp' else {}

        elements.append({
            'type': stype,
            'text': text[:100] if text else '',
            'rect': rect,
            'rect_in': {k: round(emu_to_inches(v), 3) for k, v in rect.items()},
            'fill': fill,
            'text_colors': tcolors,
            'font_sizes': [round(s/100, 1) for s in fsizes],
            'text_box_props': tbprops
        })

    return elements, slide_w, slide_h

def tag_local(tag):
    return tag.split('}')[-1] if '}' in tag else tag

for slide_num in range(1, 8):
    print(f"\n{'='*80}")
    print(f"SLIDE {slide_num}")
    print(f"{'='*80}")
    elems, sw, sh = parse_slide(slide_num)
    sw_in = round(emu_to_inches(sw), 2)
    sh_in = round(emu_to_inches(sh), 2)
    print(f"Slide size: {sw_in}\" x {sh_in}\"")

    for i, e in enumerate(elems):
        r = e['rect_in']
        print(f"\n  Element {i+1}: type={e['type']}")
        print(f"    Position: left={r['x']}\", top={r['y']}\", width={r['cx']}\", height={r['cy']}\"")
        margins = {
            'left': r['x'],
            'right': round(sw_in - r['x'] - r['cx'], 3),
            'top': r['y'],
            'bottom': round(sh_in - r['y'] - r['cy'], 3)
        }
        print(f"    Margins from edges: {margins}")
        if e['text']:
            print(f"    Text: \"{e['text'][:80]}\"")
        if e['fill']:
            print(f"    Fill: {e['fill']}")
        if e['text_colors']:
            print(f"    Text colors: {e['text_colors']}")
        if e['font_sizes']:
            print(f"    Font sizes (pt): {sorted(e['font_sizes'])}")
        if e['text_box_props']:
            print(f"    Text box insets: {e['text_box_props']}")

PYEOF

