import xml.etree.ElementTree as ET
import os

ns = {
    'a': 'http://schemas.openxmlformats.org/drawingml/2006/main',
    'r': 'http://schemas.openxmlformats.org/officeDocument/2006/relationships',
    'p': 'http://schemas.openxmlformats.org/presentationml/2006/main',
}

slides_dir = '/Users/admin/unpacked_pptx/ppt/slides'

def get_all_text_content(sp):
    """Get ALL text content including truncated parts"""
    texts = []
    for t in sp.findall('.//a:t', ns):
        if t.text:
            texts.append(t.text)
    return '|||'.join(texts)

def get_full_text(sp):
    """Get full text with paragraph breaks"""
    paras = []
    for p in sp.findall('.//a:p', ns):
        texts = []
        for t in p.findall('.//a:t', ns):
            if t.text:
                texts.append(t.text)
        if texts:
            paras.append(''.join(texts))
    return '\n'.join(paras)

def get_rect(sp):
    spPr = sp.find('.//p:spPr', ns) or sp.find('.//a:spPr', ns)
    if spPr is None:
        return None
    xfrm = spPr.find('a:xfrm', ns)
    if xfrm is None:
        return None
    off = xfrm.find('a:off', ns)
    ext = xfrm.find('a:ext', ns)
    if off is not None and ext is not None:
        return {
            'x': int(off.get('x', 0)),
            'y': int(off.get('y', 0)),
            'cx': int(off.get('cx', 0)),
            'cy': int(off.get('cy', 0))
        }
    return None

def emu_to_inches(emu):
    return emu / 914400

def tag_local(tag):
    return tag.split('}')[-1] if '}' in tag else tag

SW = 12192000  # 13.33 inches
SH = 6858000   # 7.5 inches

for slide_num in range(1, 8):
    slide_path = os.path.join(slides_dir, f'slide{slide_num}.xml')
    tree = ET.parse(slide_path)
    root = tree.getroot()

    print(f"\n{'='*80}")
    print(f"SLIDE {slide_num} - FULL TEXT CONTENT")
    print(f"{'='*80}")

    elems_with_pos = []

    for sp in root.iter():
        tag = tag_local(sp.tag)
        if tag not in ['sp', 'pic', 'grpSp', 'graphicFrame', 'cxnSp']:
            continue

        rect = get_rect(sp)
        if rect is None:
            continue

        text = get_full_text(sp)

        if tag == 'pic':
            # Get image filename
            blip = sp.find('.//a:blip', ns)
            if blip is not None:
                embed = blip.get('{http://schemas.openxmlformats.org/officeDocument/2006/relationships}embed')
                print(f"\n  Image [{embed}]: pos=({emu_to_inches(rect['x']):.2f}\", {emu_to_inches(rect['y']):.2f}\"), size=({emu_to_inches(rect['cx']):.2f}\"x{emu_to_inches(rect['cy']):.2f}\")")
        elif tag == 'sp' and text.strip():
            print(f"\n  Shape ({emu_to_inches(rect['x']):.2f}\", {emu_to_inches(rect['y']):.2f}\", {emu_to_inches(rect['cx']):.2f}\"x{emu_to_inches(rect['cy']):.2f}\"):")
            print(f"    \"{text}\"")
        elif tag == 'sp' and not text.strip():
            print(f"\n  Shape ({emu_to_inches(rect['x']):.2f}\", {emu_to_inches(rect['y']):.2f}\", {emu_to_inches(rect['cx']):.2f}\"x{emu_to_inches(rect['cy']):.2f}\") [no text / decorative]")

